class MiniMaxTTS: def init(self, api_key, group_id=None, voice_id=&quot;male-qn-qingse&quot;): self.api_key = api_key self.group_id = group_id self.voice_id = voice_id self.url = &quot;https://api.minimax.chat/v1/text_to_speech&quot;
def analyze_emotion(self, text):    &quot;&quot;&quot;简易情感分析&quot;&quot;&quot;    text_lower = text.lower()    angry_keywords = ['操', '气死', '妈的', '有病', '滚', '你什么意思', '不想理你', '生气', '恼火', '发火']    happy_keywords = ['哈哈', '笑死', '开心', '好耶', '棒', '太棒了', '爱你', '喜欢']    sad_keywords = ['难过', '伤心', '哭', '唉', '烦', '不想说话', '孤独']        if any(k in text_lower for k in angry_keywords):        return 'angry'    elif any(k in text_lower for k in happy_keywords):        return 'happy'    elif any(k in text_lower for k in sad_keywords):        return 'sad'    else:        return 'neutral'def emotion_to_params(self, emotion):    &quot;&quot;&quot;情感映射到语音参数&quot;&quot;&quot;    base = {        'emotion': emotion,        'speed': 1.0,        'pitch': 0.0    }    if emotion == 'angry':        base.update({'speed': 1.2, 'pitch': 0.2})    elif emotion == 'happy':        base.update({'speed': 1.1, 'pitch': 0.1})    elif emotion == 'sad':        base.update({'speed': 0.9, 'pitch': -0.1})    else:        base.update({'speed': 1.0, 'pitch': 0.0})    # 随机微调    base['speed'] += random.uniform(-0.05, 0.05)    base['pitch'] += random.uniform(-0.05, 0.05)    # 限制范围    base['speed'] = max(0.5, min(2.0, base['speed']))    base['pitch'] = max(-1.0, min(1.0, base['pitch']))    return basedef synthesize(self, text):    &quot;&quot;&quot;合成语音，返回音频二进制数据&quot;&quot;&quot;    emotion = self.analyze_emotion(text)    params = self.emotion_to_params(emotion)        headers = {        &quot;Authorization&quot;: f&quot;Bearer {self.api_key}&quot;,        &quot;Content-Type&quot;: &quot;application/json&quot;    }    payload = {        &quot;model&quot;: &quot;speech-01&quot;,        &quot;text&quot;: text,        &quot;voice_setting&quot;: {            &quot;voice_id&quot;: self.voice_id,            &quot;speed&quot;: params['speed'],            &quot;pitch&quot;: params['pitch'],            &quot;emotion&quot;: params['emotion']        },        &quot;audio_setting&quot;: {            &quot;sample_rate&quot;: 24000,            &quot;format&quot;: &quot;mp3&quot;        }    }    if self.group_id:        payload[&quot;group_id&quot;] = self.group_id        response = requests.post(self.url, headers=headers, json=payload)    if response.status_code == 200:        return response.content    else:        print(f&quot;TTS 错误: {response.status_code} - {response.text}&quot;)        return None
